429	    fn call_function(&mut self, name: String) -> Expr {
430	        let mut generics = vec![];
431	
432	        if self.match_any(&[TokenType::LessLess]) {
433	            loop {
434	                generics.push(self.get_type());
435	
436	                if !self.match_any(&[TokenType::Comma]) {
437	                    break;
438	                }
439	            }
440	            self.consume(TokenType::GreaterGreater, "Expected '>' after generics");
441	        }
442	
443	        self.consume(TokenType::LeftParen, "Expected '(' after function name.");
444	
445	        let mut arguments = vec![];
446	
447	        if !self.check(TokenType::RightParen) {
448	            loop {
449	                arguments.push(Box::new(self.expression()));
450	                if !self.match_any(&[TokenType::Comma]) {
451	                    break;
452	                }
453	            }
454	        }
455	
456	        self.consume(TokenType::RightParen, "Missing ')' after function call.");
457	
458	        Expr::CallFunc(name, generics, arguments, self.get_span())
459	    }
