461	    // ---------- EXPRESSIONS ----------
462	    fn expression(&mut self) -> Expr {
463	        self.assignment()
464	    }
465	
466	    fn bools(&mut self) -> Expr {
467	        let mut expr = self.compare();
468	
469	        while self.match_any(&[TokenType::And, TokenType::Or]) {
470	            let op = self.previous().token_type;
471	            let right = self.compare();
472	            expr = match op {
473	                TokenType::And => Expr::And(Box::new(expr), Box::new(right), self.get_span()),
474	                TokenType::Or => Expr::Or(Box::new(expr), Box::new(right), self.get_span()),
475	                _ => unreachable!(),
476	            };
477	        }
478	
479	        expr
480	    }
481	
482	    fn compare(&mut self) -> Expr {
483	        let mut expr = self.term();
484	
485	        while self.match_any(&[
486	            TokenType::EqualEqual,
487	            TokenType::BangEqual,
488	            TokenType::Greater,
489	            TokenType::GreaterEqual,
490	            TokenType::Less,
491	            TokenType::LessEqual,
492	        ]) {
493	            let op = self.previous().token_type;
494	            let right = self.term();
495	            expr = match op {
496	                TokenType::EqualEqual => {
497	                    Expr::EqualEqual(Box::new(expr), Box::new(right), self.get_span())
498	                }
499	                TokenType::BangEqual => {
500	                    Expr::BangEqual(Box::new(expr), Box::new(right), self.get_span())
501	                }
502	                TokenType::Greater => {
503	                    Expr::Greater(Box::new(expr), Box::new(right), self.get_span())
504	                }
505	                TokenType::GreaterEqual => {
506	                    Expr::GreaterEqual(Box::new(expr), Box::new(right), self.get_span())
507	                }
508	                TokenType::Less => Expr::Less(Box::new(expr), Box::new(right), self.get_span()),
509	                TokenType::LessEqual => {
510	                    Expr::LessEqual(Box::new(expr), Box::new(right), self.get_span())
511	                }
512	                _ => unreachable!(),
513	            };
514	        }
515	
516	        expr
517	    }
518	
519	    fn term(&mut self) -> Expr {
520	        let mut expr = self.factor();
521	
522	        while self.match_any(&[TokenType::Plus, TokenType::Minus]) {
523	            let op = self.previous().token_type;
524	            let right = self.factor();
525	            expr = match op {
526	                TokenType::Plus => Expr::Add(Box::new(expr), Box::new(right), self.get_span()),
527	                TokenType::Minus => Expr::Sub(Box::new(expr), Box::new(right), self.get_span()),
528	                _ => unreachable!(),
529	            };
530	        }
531	
532	        expr
533	    }
534	
535	    fn factor(&mut self) -> Expr {
536	        let mut expr = self.unary();
537	
538	        while self.match_any(&[TokenType::Star, TokenType::Slash, TokenType::Mod]) {
539	            let op = self.previous().token_type;
540	            let right = self.unary();
541	            expr = match op {
542	                TokenType::Star => Expr::Mult(Box::new(expr), Box::new(right), self.get_span()),
543	                TokenType::Slash => Expr::Div(Box::new(expr), Box::new(right), self.get_span()),
544	                TokenType::Mod => Expr::Mod(Box::new(expr), Box::new(right), self.get_span()),
545	                _ => unreachable!(),
546	            };
547	        }
548	
549	        expr
550	    }
551	
552	    fn unary(&mut self) -> Expr {
553	        if self.match_any(&[TokenType::Minus]) {
554	            return Expr::Sub(
555	                Box::new(Expr::Nothing()),
556	                Box::new(self.unary()),
557	                self.get_span(),
558	            );
559	        }
560	
561	        if self.match_any(&[TokenType::Plus]) {
562	            return Expr::Add(
563	                Box::new(Expr::Nothing()),
564	                Box::new(self.unary()),
565	                self.get_span(),
566	            );
567	        }
568	
569	        if self.match_any(&[TokenType::Bang]) {
570	            return Expr::Not(Box::new(self.unary()), self.get_span());
571	        }
572	
573	        if self.match_any(&[TokenType::And]) {
574	            // ref: create a reference to a variable
575	            return if self.check(TokenType::Ident) {
576	                self.advance(); // consume the identifier
577	                let inner = Box::new(Expr::Variable(
578	                    self.previous().lexeme.clone(),
579	                    self.get_span(),
580	                ));
581	                Expr::Ref(inner, self.get_span())
582	            } else {
583	                error(self.get_span(), "Expected identifier after '&'.", "parsing");
584	                Expr::Nothing()
585	            };
586	        }
587	
588	        if self.match_any(&[TokenType::Star]) {
589	            let inner = Box::new(self.unary());
590	            return Expr::Deref(inner, self.get_span());
591	        }
592	
593	        self.power()
594	    }
595	
596	    fn power(&mut self) -> Expr {
597	        let mut expr = self.member();
598	
599	        while self.match_any(&[TokenType::StarStar]) {
600	            expr = Expr::Power(Box::new(expr), Box::new(self.member()), self.get_span());
601	        }
602	
603	        expr
604	    }
605	    fn nth(&mut self) -> Expr {
606	        let val = self.primary();
607	        if self.match_any(&[TokenType::LeftBrack]) {
608	            let expr = self.expression();
609	            self.consume(TokenType::RightBrack, "Expected ']' after indexing.");
610	            Expr::Nth(Box::new(val), Box::new(expr), self.get_span())
611	        } else {
612	            val
613	        }
614	    }
615	
616	    fn vector_lit(&mut self) -> Expr {
617	        if self.match_any(&[TokenType::LeftBrace]) {
618	            let mut exprs = vec![];
619	
620	            let mut last_expr = false;
621	            while !self.match_any(&[TokenType::RightBrace]) && !last_expr {
622	                let expr = self.expression();
623	                exprs.push(expr);
624	                if !self.match_any(&[TokenType::Comma]) {
625	                    last_expr = true;
626	                }
627	            }
628	
629	            Expr::Vector(exprs)
630	        } else {
631	            self.consume(TokenType::LeftBrace, "Expected '{' after '\\''.");
632	            Expr::Nothing()
633	        }
634	    }
635	
636	    fn array_lit(&mut self) -> Expr {
637	        let mut exprs = vec![];
638	
639	        let mut last_expr = false;
640	        while !self.match_any(&[TokenType::RightBrack]) && !last_expr {
641	            let expr = self.expression();
642	            exprs.push(expr);
643	            if !self.match_any(&[TokenType::Comma]) {
644	                last_expr = true;
645	            }
646	        }
647	
648	        Expr::Array(exprs)
649	    }
650	
651	    // ---------- PRIMARY ----------
652	    fn primary(&mut self) -> Expr {
653	        if self.match_any(&[TokenType::LeftBrace]) {
654	            return self.statement_block();
655	        }
656	
657	        if self.check(TokenType::Ident) {
658	            let item = self.item();
659	
660	            if self.check(TokenType::LeftParen) || self.check(TokenType::LessLess) {
661	                return self.call_function(item);
662	            }
663	            return Expr::Variable(item, self.get_span());
664	        }
665	
666	        if self.match_any(&[TokenType::Float]) {
667	            return Expr::Float(self.previous().literal.parse().unwrap_or(0.0));
668	        }
669	
670	        if self.match_any(&[TokenType::Int]) {
671	            return Expr::Int(self.previous().literal.parse().unwrap_or(0));
672	        }
673	
674	        if self.match_any(&[TokenType::True]) {
675	            return Expr::Bool(true);
676	        }
677	
678	        if self.match_any(&[TokenType::False]) {
679	            return Expr::Bool(false);
680	        }
681	
682	        if self.match_any(&[TokenType::String]) {
683	            return Expr::Str(self.previous().literal.clone());
684	        }
685	
686	        if self.match_any(&[TokenType::Char]) {
687	            return Expr::Char(self.previous().literal.clone());
688	        }
689	
690	        if self.match_any(&[TokenType::LeftParen]) {
691	            let expr = self.expression();
692	            self.consume(TokenType::RightParen, "Expected ')'.");
693	            return expr;
694	        }
695	
696	        if self.match_any(&[TokenType::QuestionMark]) {
697	            return self.if_statement(true);
698	        }
699	
700	        if self.match_any(&[TokenType::This]) {
701	            return Expr::This(self.get_span());
702	        }
703	
704	        if self.match_any(&[TokenType::Lam]) {
705	            return self.define_lambda();
706	        }
707	
708	        if self.match_any(&[TokenType::BackSlash]) {
709	            return self.vector_lit();
710	        }
711	
712	        if self.match_any(&[TokenType::LeftBrack]) {
713	            return self.array_lit();
714	        }
715	
716	        Expr::Nothing()
717	    }
718	
719	    fn get_type(&mut self) -> Type {
720	        if self.match_any(&[TokenType::Ident]) {
721	            let name = self.previous().lexeme.clone();
722	
723	            if self.match_any(&[TokenType::LessLess]) {
724	                let mut gens = vec![];
725	
726	                loop {
727	                    gens.push(self.get_type());
728	                    if !self.match_any(&[TokenType::Comma]) {
729	                        break;
730	                    }
731	                }
732	
733	                self.consume(TokenType::GreaterGreater, "Expected '>' after generics");
734	                return Type::with_generics(&name, gens);
735	            }
736	
737	            return Type::simple(&name);
738	        } else if self.match_any(&[TokenType::LeftBrack]) {
739	            let mut gens = vec![];
740	
741	            loop {
742	                gens.push(self.get_type());
743	                if !self.match_any(&[TokenType::Comma]) {
744	                    break;
745	                }
746	            }
747	
748	            self.consume(TokenType::RightBrack, "Expected '>' after generics");
749	            return Type::with_generics("arr", gens);
750	        } else if self.match_any(&[TokenType::And]) {
751	            return Type::with_generics("ref", vec![self.get_type()]);
752	        }
753	
754	        error(self.get_span(), "Expected type", "parsing");
755	
756	        nil_type()
757	    }
758	
759	    // ---------- UTIL ----------
760	    fn get_span(&self) -> Span {
761	        let token = self.previous();
762	        Span {
763	            line: token.line,
764	            column: token.column,
765	        }
766	    }
767	
768	    fn item(&mut self) -> String {
769	        self.consume(TokenType::Ident, "Expected item.");
770	        let item = self.previous().lexeme.clone();
771	        item
772	    }
773	
774	    fn ident(&mut self) -> String {
775	        self.consume(TokenType::Ident, "Expected identifier.");
776	        let ident = self.previous().lexeme.clone();
777	        ident
778	    }
779	
780	    fn match_any(&mut self, types: &[TokenType]) -> bool {
781	        for t in types {
782	            if self.check(*t) {
783	                self.advance();
784	                return true;
785	            }
786	        }
787	        false
788	    }
789	    fn check(&self, token_type: TokenType) -> bool {
790	        !self.is_at_end() && self.peek().token_type == token_type
791	    }
792	
793	    fn peek_next(&self, token_type: TokenType) -> bool {
794	        self.tokens
795	            .get(self.current + 1)
796	            .map(|t| t.token_type == token_type)
797	            .unwrap_or(false)
798	    }
799	
800	    fn peek_next_next(&self, token_type: TokenType) -> bool {
801	        self.tokens
802	            .get(self.current + 2)
803	            .map(|t| t.token_type == token_type)
804	            .unwrap_or(false)
805	    }
806	
807	    fn consume(&mut self, token_type: TokenType, message: &str) -> Token {
808	        if self.check(token_type) {
809	            self.advance()
810	        } else {
811	            let t = self.peek();
812	            error(
813	                self.get_span(),
814	                format!("{} Found: {}", message, t.token_type).as_str(),
815	                "parsing",
816	            );
817	            self.advance();
818	            Token::nil()
819	        }
820	    }
821	
822	    fn advance(&mut self) -> Token {
823	        if !self.is_at_end() {
824	            self.current += 1;
825	        }
826	        self.previous()
827	    }
828	
829	    fn is_at_end(&self) -> bool {
830	        self.peek().token_type == TokenType::EOF
831	    }
832	
833	    fn peek(&self) -> Token {
834	        self.tokens
835	            .get(self.current)
836	            .cloned()
837	            .unwrap_or_else(Token::nil)
838	    }
839	
840	    fn previous(&self) -> Token {
841	        self.tokens
842	            .get(self.current.saturating_sub(1))
843	            .cloned()
844	            .unwrap_or_else(Token::nil)
845	    }
846	}
847	
848	// Grammar:
849	/*
850	statement_block -> "{" ( statement )* "}"
851	statement       -> ( print | declaration | expression | return | function ) ";"
852	
853	print           -> "$" ( "$" )? expression
854	declaration     -> "#" ( "@" )? IDENTIFIER ( ":" type )? ( "=" expression )? // need one or both
855	return          -> "ret" expression
856	while           -> "£" expression statement_block
857	
858	if_statement    -> "?" expression statement_block ( "~?" expression statement_block )* ( "~" statement_block )?
859	function_call   -> IDENTIFIER "(" (expression)* ")"
860	function        -> "fn" ( "<<" IDENTIFIER* ">>" )? IDENTIFIER ( "(" (IDENTIFIER ":" IDENTIFIER)* ")" )? type? statement_block
861	
862	type            -> IDENTIFIER | "[" type* "]" | "<<" type* ">>"
863	
864	expression      -> bool
865	bool            -> compare ( ( "&" | "|" ) compare )*
866	compare         -> term ( ( "==" | ">=" | "<=" | ">" | "<" | "!=" ) term )*
867	term            -> factor ( ( "+" | "-" ) factor )*
868	factor          -> unary ( ( "*" | "/" | "%" ) unary )*
869	unary           -> ( "-" | "+" ) unary | power
870	power           -> nth ( ( "**" ) nth )*
871	nth             -> primary ( "[" expression "]" )?
872	primary         -> NUMBER | STRING | BOOLEAN | IDENTIFIER | "(" expression ")" | statement_block | if_statement | function_call
873	
874	*/
875

1	use crate::error;
2	use crate::span::Span;
3	use crate::token::Token;
4	use crate::token_type::TokenType;
5	use std::collections::HashMap;
6	
7	pub struct Scanner {
8	    source: String,
9	    tokens: Vec<Token>,
10	    start: usize,
11	    current: usize,
12	    line: usize,
13	    column: usize,
14	    keywords: HashMap<String, TokenType>,
15	    prev_c: char,
16	}
17	
18	impl Scanner {
19	    pub fn new(source: String) -> Self {
20	        let mut keywords = HashMap::new();
21	
22	        keywords.insert("cls".into(), TokenType::Cls);
23	        keywords.insert("ret".into(), TokenType::Ret);
24	        keywords.insert("comp".into(), TokenType::Comp);
25	        keywords.insert("stc".into(), TokenType::Stc);
26	        keywords.insert("ovr".into(), TokenType::Ovr);
27	        keywords.insert("err".into(), TokenType::Err);
28	        keywords.insert("del".into(), TokenType::Del);
29	        keywords.insert("use".into(), TokenType::Use);
30	        keywords.insert("for".into(), TokenType::For);
31	        keywords.insert("fn".into(), TokenType::Fn);
32	        keywords.insert("mac".into(), TokenType::Mac);
33	        keywords.insert("lam".into(), TokenType::Lam);
34	        keywords.insert("std".into(), TokenType::Std);
35	
36	        Scanner {
37	            source,
38	            tokens: Vec::new(),
39	            start: 0,
40	            current: 0,
41	            line: 1,
42	            column: 1,
43	            keywords,
44	            prev_c: '\0',
45	        }
46	    }
47	
48	    pub fn scan_tokens(&mut self) -> &Vec<Token> {
49	        while !self.is_at_end() {
50	            self.start = self.current;
51	            self.scan_token();
52	        }
53	
54	        self.tokens.push(Token::new(
55	            TokenType::EOF,
56	            String::new(),
57	            String::new(),
58	            self.line,
59	            self.column,
60	        ));
61	        &self.tokens
62	    }
63	
64	    fn is_at_end(&self) -> bool {
65	        self.current >= self.source.len()
66	    }
67	
68	    fn scan_token(&mut self) {
69	        let c = self.advance();
70	        match c {
71	            '(' => self.add_token(TokenType::LeftParen),
72	            ')' => self.add_token(TokenType::RightParen),
73	            '{' => self.add_token(TokenType::LeftBrace),
74	            '}' => self.add_token(TokenType::RightBrace),
75	            '[' => self.add_token(TokenType::LeftBrack),
76	            ']' => self.add_token(TokenType::RightBrack),
77	            '&' => self.add_token(TokenType::And),
78	            '|' => self.add_token(TokenType::Or),
79	            ',' => self.add_token(TokenType::Comma),
80	            '.' => self.add_token(TokenType::Dot),
81	            '%' => self.add_token(TokenType::Mod),
82	            '-' => {
83	                if self.match_char('>') {
84	                    self.add_token(TokenType::MinusRight);
85	                } else {
86	                    self.add_token(TokenType::Minus);
87	                }
88	            }
89	            '+' => self.add_token(TokenType::Plus),
90	            ';' => self.add_token(TokenType::Semicolon),
91	            ':' => {
92	                if self.match_char(':') {
93	                    self.add_token(TokenType::DoubleColon);
94	                } else {
95	                    self.add_token(TokenType::Colon);
96	                }
97	            }
98	            '*' => {
99	                if self.match_char('*') {
100	                    self.add_token(TokenType::StarStar);
101	                } else {
102	                    self.add_token(TokenType::Star);
103	                }
104	            }
105	            '~' => {
106	                if self.match_char('?') {
107	                    self.add_token(TokenType::TildeQuestionMark);
108	                } else {
109	                    self.add_token(TokenType::Tilde);
110	                }
111	            }
112	            '?' => self.add_token(TokenType::QuestionMark),
113	            '$' => {
114	                if self.match_char('?') {
115	                    self.add_token(TokenType::DollarQuestionMark);
116	                } else {
117	                    self.add_token(TokenType::Dollar);
118	                }
119	            }
120	            '^' => {
121	                if self.match_char('^') {
122	                    self.add_token(TokenType::DoubleUpArrow);
123	                } else {
124	                    self.add_token(TokenType::UpArrow);
125	                }
126	            }
127	            '!' => {
128	                if self.match_char('=') {
129	                    self.add_token(TokenType::BangEqual);
130	                } else {
131	                    self.add_token(TokenType::Bang);
132	                }
133	            }
134	            '=' => {
135	                if self.match_char('=') {
136	                    self.add_token(TokenType::EqualEqual);
137	                } else {
138	                    self.add_token(TokenType::Equal);
139	                }
140	            }
141	            '<' => {
142	                if self.match_char('=') {
143	                    self.add_token(TokenType::LessEqual);
144	                } else if self.match_char('<') {
145	                    self.add_token(TokenType::LessLess);
146	                } else {
147	                    self.add_token(TokenType::Less);
148	                }
149	            }
150	            '>' => {
151	                if self.match_char('=') {
152	                    self.add_token(TokenType::GreaterEqual);
153	                } else if self.match_char('>') {
154	                    self.add_token(TokenType::GreaterGreater);
155	                } else {
156	                    self.add_token(TokenType::Greater);
157	                }
158	            }
159	            '#' => {
160	                self.add_token(TokenType::Hash);
161	            }
162	            '@' => self.add_token(TokenType::At),
163	            '£' => self.add_token(TokenType::Pound),
164	            '¬' => self.add_token(TokenType::NotSign),
165	            '/' => {
166	                if self.match_char('/') {
167	                    // Single-line comment
168	                    while self.peek() != '\n' && !self.is_at_end() {
169	                        self.advance();
170	                    }
171	                } else if self.match_char('*') {
172	                    // Multi-line comment
173	                    self.block_comment();
174	                } else {
175	                    self.add_token(TokenType::Slash);
176	                }
177	            }
178	            '\\' => self.add_token(TokenType::BackSlash),
179	            ' ' | '\r' | '\t' | '\n' => {}
180	            '`' => self.backtick(),
181	            '"' => self.string(),
182	            '\'' => self.character(),
183	            _ => {
184	                if c.is_ascii_digit() {
185	                    self.number();
186	                } else if self.alpha(c) {
187	                    self.identifier();
188	                } else {
189	                    error(
190	                        Span {
191	                            line: self.line,
192	                            column: self.column,
193	                        },
194	                        "Unexpected character.",
195	                        "scanning",
196	                    );
197	                }
198	            }
199	        }
200	    }
201	
202	    fn advance(&mut self) -> char {
203	        let c = self.source[self.current..].chars().next().unwrap();
204	        self.current += c.len_utf8();
205	
206	        if c == '\n' {
207	            self.line += 1;
208	            self.column = 1;
209	        } else {
210	            self.column += 1;
211	        }
212	
213	        c
214	    }
215	
216	    fn add_token(&mut self, token_type: TokenType) {
217	        self.add_token_literal(token_type, "".into());
218	    }
219	
220	    fn add_token_literal(&mut self, token_type: TokenType, literal: String) {
221	        let text = self.source[self.start..self.current].to_string();
222	
223	        let token_column = self.column - text.chars().count();
224	
225	        self.tokens.push(Token::new(
226	            token_type,
227	            text,
228	            literal,
229	            self.line,
230	            token_column.max(1),
231	        ));
232	    }
233	
234	    fn match_char(&mut self, expected: char) -> bool {
235	        if self.is_at_end() {
236	            return false;
237	        }
238	
239	        if self.peek() != expected {
240	            return false;
241	        }
242	
243	        self.advance();
244	        true
245	    }
246	
247	    fn peek(&self) -> char {
248	        if self.is_at_end() {
249	            '\0'
250	        } else {
251	            self.source[self.current..].chars().next().unwrap()
252	        }
253	    }
254	
255	    fn peek_next(&self) -> char {
256	        let mut chars = self.source[self.current..].chars();
257	        chars.next();
258	        chars.next().unwrap_or('\0')
259	    }
260	
261	    fn alpha(&mut self, c: char) -> bool {
262	        let output =
263	            (c.is_ascii_alphabetic() || c == '_' || c == '¬') && !(c == '_' && self.prev_c == '_');
264	        self.prev_c = c;
265	        output
266	    }
267	
268	    fn alpha_numeric(&mut self, c: char) -> bool {
269	        self.alpha(c) || c.is_ascii_digit()
270	    }
271	
272	    fn string(&mut self) {
273	        let mut value = String::new();
274	
275	        while !self.is_at_end() {
276	            let c = self.advance();
277	
278	            match c {
279	                '"' => {
280	                    // End of string
281	                    self.add_token_literal(TokenType::String, value);
282	                    return;
283	                }
284	                '\\' => {
285	                    if self.is_at_end() {
286	                        error(
287	                            Span {
288	                                line: self.line,
289	                                column: self.column,
290	                            },
291	                            "Unterminated escape sequence in string.",
292	                            "lexing",
293	                        );
294	                        return;
295	                    }
296	
297	                    let esc = self.advance();
298	                    match esc {
299	                        'n' => value.push('\n'),
300	                        't' => value.push('\t'),
301	                        'r' => value.push('\r'),
302	                        '\\' => value.push('\\'),
303	                        'x' => value.push_str("\\x"),
304	                        '0' => value.push_str("\0"),
305	                        '"' => value.push('"'),
306	                        _ => {
307	                            error(
308	                                Span {
309	                                    line: self.line,
310	                                    column: self.column,
311	                                },
312	                                &format!("Invalid escape sequence: \\{}", esc),
313	                                "lexing",
314	                            );
315	                            return;
316	                        }
317	                    }
318	                }
319	                _ => value.push(c),
320	            }
321	        }
322	
323	        error(
324	            Span {
325	                line: self.line,
326	                column: self.column,
327	            },
328	            "Unterminated string literal.",
329	            "lexing",
330	        );
331	    }
332	
333	    fn number(&mut self) {
334	        while self.peek().is_ascii_digit() {
335	            self.advance();
336	        }
337	
338	        // Look for fractional part
339	        if self.peek() == '.' && self.peek_next().is_ascii_digit() {
340	            self.advance(); // consume '.'
341	            while self.peek().is_ascii_digit() {
342	                self.advance();
343	            }
344	            let value = self.source[self.start..self.current].to_string();
345	            self.add_token_literal(TokenType::Float, value);
346	        } else {
347	            let value = self.source[self.start..self.current].to_string();
348	            self.add_token_literal(TokenType::Int, value);
349	        }
350	    }
351	
352	    fn identifier(&mut self) {
353	        while self.alpha_numeric(self.peek()) {
354	            self.advance();
355	        }
356	
357	        // Handle '::' type sequences like 'str::i32'
358	        while self.peek() == ':' && self.peek_next() == ':' {
359	            self.advance(); // consume first ':'
360	            self.advance(); // consume second ':'
361	
362	            // continue scanning the next identifier part
363	            while self.alpha_numeric(self.peek()) {
364	                self.advance();
365	            }
366	        }
367	
368	        let text = self.source[self.start..self.current].to_string();
369	        if let Some(token_type) = self.keywords.get(&text) {
370	            self.add_token(*token_type);
371	        } else {
372	            self.add_token(TokenType::Ident);
373	        }
374	    }
375	
376	    fn character(&mut self) {
377	        if self.is_at_end() {
378	            error(
379	                Span {
380	                    line: self.line,
381	                    column: self.column,
382	                },
383	                "Unterminated character literal.",
384	                "lexing",
385	            );
386	            return;
387	        }
388	
389	        let c = self.advance();
390	        let value = if c == '\\' {
391	            if self.is_at_end() {
392	                error(
393	                    Span {
394	                        line: self.line,
395	                        column: self.column,
396	                    },
397	                    "Unterminated escape sequence.",
398	                    "lexing",
399	                );
400	                return;
401	            }
402	            let esc = self.advance();
403	            match esc {
404	                'n' => "\n".to_string(),
405	                't' => "\t".to_string(),
406	                '\\' => "\\".to_string(),
407	                '\'' => "'".to_string(),
408	                'r' => "\r".to_string(),
409	                '0' => "\0".to_string(),
410	                _ => {
411	                    error(
412	                        Span {
413	                            line: self.line,
414	                            column: self.column,
415	                        },
416	                        &format!("Invalid escape sequence: \\{}", esc),
417	                        "lexing",
418	                    );
419	                    return;
420	                }
421	            }
422	        } else {
423	            c.to_string()
424	        };
425	
426	        if self.peek() != '\'' {
427	            error(
428	                Span {
429	                    line: self.line,
430	                    column: self.column,
431	                },
432	                "Character literal too long or missing closing quote.",
433	                "lexing",
434	            );
435	            return;
436	        }
437	
438	        self.advance(); // Consume closing quote
439	        self.add_token_literal(TokenType::Char, value);
440	    }
441	
442	    fn backtick(&mut self) {
443	        if self.is_at_end() {
444	            error(
445	                Span {
446	                    line: self.line,
447	                    column: self.column,
448	                },
449	                "Expected character after backtick (`)",
450	                "lexing",
451	            );
452	            return;
453	        }
454	
455	        let c = self.advance();
456	        match c {
457	            'f' => self.add_token(TokenType::False),
458	            't' => self.add_token(TokenType::True),
459	            's' => self.tokens.push(Token::new(
460	                TokenType::String,
461	                String::new(),
462	                String::new(),
463	                self.line,
464	                self.column,
465	            )),
466	            'v' => self.add_token(TokenType::This),
467	            _ => {
468	                error(
469	                    Span {
470	                        line: self.line,
471	                        column: self.column,
472	                    },
473	                    "Invalid character after backtick (`)",
474	                    "lexing",
475	                );
476	                return;
477	            }
478	        }
479	
480	        if self.alpha(self.peek()) {
481	            error(
482	                Span {
483	                    line: self.line,
484	                    column: self.column,
485	                },
486	                "Only a single character should be after a backtick (`)",
487	                "lexing",
488	            );
489	        }
490	    }
491	
492	    fn block_comment(&mut self) {
493	        while !self.is_at_end() {
494	            if self.peek() == '*' {
495	                self.advance();
496	                if self.peek() == '/' {
497	                    self.advance();
498	                    return;
499	                }
500	            } else {
501	                self.advance();
502	            }
503	        }
504	
505	        error(
506	            Span {
507	                line: self.line,
508	                column: self.column,
509	            },
510	            "Unterminated block comment.",
511	            "lexing",
512	        );
513	    }
514	}
