1	use crate::span::Span;
2	use core::fmt;
3	use std::collections::HashMap;
4	
5	#[derive(Clone)]
6	pub struct TypeEnvironment {
7	    scopes: Vec<HashMap<String, Type>>,
8	    gens: Vec<HashMap<String, Type>>,
9	}
10	
11	impl TypeEnvironment {
12	    pub fn new() -> Self {
13	        Self {
14	            scopes: vec![HashMap::new()],
15	            gens: vec![HashMap::new()],
16	        }
17	    }
18	
19	    pub fn push(&mut self) {
20	        self.scopes.push(HashMap::new());
21	    }
22	
23	    pub fn pop(&mut self) {
24	        self.scopes.pop();
25	    }
26	
27	    pub fn push_func(&mut self) {
28	        self.gens.push(HashMap::new());
29	    }
30	
31	    pub fn pop_func(&mut self) {
32	        self.gens.pop();
33	    }
34	
35	    pub fn get_gen(&mut self, name: String) -> Type {
36	        self.gens.last().unwrap().get(&name).unwrap().clone()
37	    }
38	
39	    pub fn add_gen(&mut self, name: String, ty: Type) {
40	        self.gens.last_mut().unwrap().insert(name, ty);
41	    }
42	
43	    pub fn declare(&mut self, name: String, ty: Type) {
44	        self.scopes.last_mut().unwrap().insert(name, ty);
45	    }
46	
47	    pub fn get(&self, name: &str) -> Type {
48	        for scope in self.scopes.iter().rev() {
49	            if let Some(t) = scope.get(name) {
50	                return t.clone();
51	            }
52	        }
53	
54	        panic!("Type error: unknown variable {}", name);
55	    }
56	}
57	
58	#[derive(Debug, Clone, PartialEq, Eq, Hash)]
59	pub enum Type {
60	    Concrete { name: String, generics: Vec<Type> }, // vec<<i32>>
61	    Conceptual(String),                             // T, U, etc
62	    Generic { name: String, generics: usize },      // vec, 1
63	}
64	
65	impl Type {
66	    pub fn simple(name: &str) -> Self {
67	        Type::Concrete {
68	            name: name.into(),
69	            generics: vec![],
70	        }
71	    }
72	
73	    pub fn is_conceptual(&self) -> bool {
74	        matches!(self, Type::Conceptual(_))
75	    }
76	    pub fn is_generics(&self) -> bool {
77	        matches!(self, Type::Generic { .. })
78	    }
79	
80	    pub fn has_generics(&self) -> bool {
81	        if let Type::Concrete { name: _, generics } = self {
82	            generics.len() >= 1
83	        } else {
84	            false
85	        }
86	    }
87	
88	    pub fn conceptual(name: &str) -> Self {
89	        Type::Conceptual(name.into())
90	    }
91	
92	    pub fn generics(&self) -> &[Type] {
93	        match self {
94	            Type::Concrete { generics, .. } => generics,
95	            _ => &[],
96	        }
97	    }
98	
99	    pub fn with_generics(name: &str, gens: Vec<Type>) -> Self {
100	        Type::Concrete {
101	            name: name.into(),
102	            generics: gens,
103	        }
104	    }
105	
106	    pub fn name(&self) -> &str {
107	        match self {
108	            Type::Concrete { name, .. } => name,
109	            Type::Conceptual(n) => n,
110	            Type::Generic { name, .. } => name,
111	        }
112	    }
113	
114	    pub fn has_tag(&self, tag: &str) -> bool {
115	        self.name() == tag
116	    }
117	}
118	
119	impl From<&str> for Type {
120	    fn from(name: &str) -> Self {
121	        Type::simple(name)
122	    }
123	}
124	
125	impl From<String> for Type {
126	    fn from(name: String) -> Self {
127	        Type::simple(&name)
128	    }
129	}
130	
131	impl fmt::Display for Type {
132	    fn fmt(&self, f: &mut std::fmt::Formatter) -> std::fmt::Result {
133	        match self {
134	            Type::Conceptual(n) => write!(f, "{}", n),
135	            Type::Concrete { name, generics } => {
136	                if generics.is_empty() {
137	                    write!(f, "{}", name)
138	                } else {
139	                    let g = generics
140	                        .iter()
141	                        .map(|x| x.to_string())
142	                        .collect::<Vec<_>>()
143	                        .join(", ");
144	                    write!(f, "{}<<{}>>", name, g)
145	                }
146	            }
147	            Type::Generic { name, generics } => {
148	                write!(f, "{}<<{}>>", name, generics)
149	            }
150	        }
151	    }
152	}
153	
154	pub fn nil_type() -> Type {
155	    Type::simple("arr")
156	}
157	
158	pub fn unify(pattern: &Type, actual: &Type, bindings: &mut HashMap<String, Type>) -> bool {
159	    match (pattern, actual) {
160	        (Type::Conceptual(name), t) => {
161	            if let Some(bound) = bindings.get(name) {
162	                bound == t
163	            } else {
164	                bindings.insert(name.clone(), t.clone());
165	                true
166	            }
167	        }
168	
169	        (
170	            Type::Concrete {
171	                name: a,
172	                generics: ag,
173	            },
174	            Type::Concrete {
175	                name: b,
176	                generics: bg,
177	            },
178	        ) => {
179	            if a != b || ag.len() != bg.len() {
180	                return false;
181	            }
182	
183	            for (x, y) in ag.iter().zip(bg.iter()) {
184	                if !unify(x, y, bindings) {
185	                    return false;
186	                }
187	            }
188	            true
189	        }
190	
191	        _ => false,
192	    }
193	}
194	
195	pub fn substitute(t: &Type, map: &HashMap<String, Type>, span: Span) -> Type {
196	    match t {
197	        Type::Conceptual(n) => map.get(n).cloned().unwrap_or(t.clone()),
198	
199	        Type::Concrete { name, generics } => Type::Concrete {
200	            name: name.clone(),
201	            generics: generics.iter().map(|g| substitute(g, map, span)).collect(),
202	        },
203	        Type::Generic { .. } => {
204	            todo!()
205	        }
206	    }
207	}
