10	/// Helper to transpile source to C code
11	fn transpile_to_c(source: &str) -> String {
12	    let mut scanner = Scanner::new(source.to_string());
13	    let tokens = scanner.scan_tokens();
14	    let mut parser = Parser::new(tokens);
15	    let expr = parser.parse();
16	
17	    let mut ctx = CodeGenContext::new();
18	    let mut cte = CompileTimeEnv::new(&mut ctx);
19	
20	    expr.pre_transpile(&mut cte, &mut ctx, &mut HashMap::new(), "");
21	    expr.to_c(&mut cte, &mut ctx);
22	    ctx.combine(&mut cte)
23	}
24	
25	/// Helper to get the types section from generated C
26	fn get_types_section(source: &str) -> String {
27	    let c = transpile_to_c(source);
28	    // Extract the typedef section
29	    if let Some(start) = c.find("typedef") {
30	        return c[start..]
31	            .lines()
32	            .take_while(|line| line.contains("typedef") || line.trim().is_empty())
33	            .collect();
34	    }
35	    String::new()
36	}
37	
38	/// Helper to get just the body of generated C code
39	fn transpile_body(source: &str) -> String {
40	    let c = transpile_to_c(source);
41	    // Extract just the main function body
42	    if let Some(start) = c.find("main() {") {
43	        let body_start = start + "main() {".len();
44	        if let Some(end) = c[body_start..].find("}") {
45	            return c[body_start..body_start + end].to_string();
46	        }
47	    }
48	    c
49	}
