488	    let source = r#"
489	fn add(a: i32, b: i32) i32 {
490	    ret a + b;
491	}
492	"#;
493	    let c = transpile_to_c(source);
494	
495	    // The D marker must be at the very end of the mangled name
496	    // Format: t_5C{all_types}D where all_types includes args AND return type
497	    // For func(i32, i32) -> i32: t_5Ct_0_t_0_t_0D
498	    // Not: t_5C{args}D{ret} which would be wrong
