500	    // Verify D is at the end by checking the pattern
501	    assert!(
502	        c.contains("t_5Ct_0_t_0_t_0D"),
503	        "D marker should be at the very end"
504	    );
505	
506	    // Make sure there's no pattern like t_5C...D... (D in the middle)
507	    let lines: Vec<&str> = c.lines().collect();
508	    for line in lines {
509	        if line.contains("typedef") && line.contains("t_5") {
510	            // Extract the mangled type name
511	            if let Some(start) = line.find("t_5C") {
512	                let rest = &line[start..];
513	                // D should be the last character before the closing paren or semicolon
514	                if let Some(end) = rest.find(")") {
515	                    let mangled = &rest[..end];
516	                    assert!(
517	                        mangled.ends_with('D'),
518	                        "Mangled type '{}' should end with D",
519	                        mangled
520	                    );
521	                }
522	            }
523	        }
524	    }
